548 static std::optional<unsigned> getInsertExtractIndex(const Value *Inst,
549                                                      unsigned Offset) {
550   static_assert(std::is_same_v<T, InsertElementInst> ||
551                     std::is_same_v<T, ExtractElementInst>,
552                 "unsupported T");
553   int Index = Offset;
