 861     AShrBIT = 0b10,
 862     MulBIT = 0b100,
 863     AddBIT = 0b1000,
 864     SubBIT = 0b10000,
 865     AndBIT = 0b100000,
 866     OrBIT = 0b1000000,
 867     XorBIT = 0b10000000,
