2800     /// \returns the maximum number of operands that are allowed to be reordered
2801     /// for \p Lane and the number of compatible instructions(with the same
2802     /// parent/opcode). This is used as a heuristic for selecting the first lane
2803     /// to start operand reordering.
2804     OperandsOrderData getMaxNumOperandsThatCanBeReordered(unsigned Lane) const {
2805       unsigned CntTrue = 0;
2806       unsigned NumOperands = getNumOperands();
2807       // Operands with the same APO can be reordered. We therefore need to count
2808       // how many of them we have for each APO, like this: Cnt[APO] = x.
2809       // Since we only have two APOs, namely true and false, we can avoid using
2810       // a map. Instead we can simply count the number of operands that
2811       // correspond to one of them (in this case the 'true' APO), and calculate
2812       // the other by subtracting it from the total number of operands.
2813       // Operands with the same instruction opcode and parent are more
2814       // profitable since we don't need to move them in many cases, with a high
2815       // probability such lane already can be vectorized effectively.
2816       bool AllUndefs = true;
2817       unsigned NumOpsWithSameOpcodeParent = 0;
2818       Instruction *OpcodeI = nullptr;
2819       BasicBlock *Parent = nullptr;
2820       unsigned Hash = 0;
2821       for (unsigned OpIdx = 0; OpIdx != NumOperands; ++OpIdx) {
2822         const OperandData &OpData = getData(OpIdx, Lane);
2823         if (OpData.APO)
2824           ++CntTrue;
2825         // Use Boyer-Moore majority voting for finding the majority opcode and
2826         // the number of times it occurs.
2827         if (auto *I = dyn_cast<Instruction>(OpData.V)) {
2828           if (!OpcodeI || !getSameOpcode({OpcodeI, I}, TLI) ||
2829               I->getParent() != Parent) {
2830             if (NumOpsWithSameOpcodeParent == 0) {
2831               NumOpsWithSameOpcodeParent = 1;
2832               OpcodeI = I;
2833               Parent = I->getParent();
2834             } else {
2835               --NumOpsWithSameOpcodeParent;
2836             }
2837           } else {
2838             ++NumOpsWithSameOpcodeParent;
2839           }
2840         }
2841         Hash = hash_combine(
2842             Hash, hash_value((OpIdx + 1) * (OpData.V->getValueID() + 1)));
2843         AllUndefs = AllUndefs && isa<UndefValue>(OpData.V);
2844       }
2845       if (AllUndefs)
2846         return {};
2847       OperandsOrderData Data;
2848       Data.NumOfAPOs = std::max(CntTrue, NumOperands - CntTrue);
2849       Data.NumOpsWithSameOpcodeParent = NumOpsWithSameOpcodeParent;
2850       Data.Hash = Hash;
2851       return Data;
2852     }
