2922     /// \Returns true if there are enough operands identical to \p Op to fill
2923     /// the whole vector (it is mixed with constants or loop invariant values).
2924     /// Note: This modifies the 'IsUsed' flag, so a cleanUsed() must follow.
2925     bool shouldBroadcast(Value *Op, unsigned OpIdx, unsigned Lane) {
2926       assert(Op == getValue(OpIdx, Lane) &&
2927              "Op is expected to be getValue(OpIdx, Lane).");
2928       // Small number of loads - try load matching.
2929       if (isa<LoadInst>(Op) && getNumLanes() == 2 && getNumOperands() == 2)
2930         return false;
2931       bool OpAPO = getData(OpIdx, Lane).APO;
2932       bool IsInvariant = L && L->isLoopInvariant(Op);
2933       unsigned Cnt = 0;
2934       for (unsigned Ln = 0, Lns = getNumLanes(); Ln != Lns; ++Ln) {
2935         if (Ln == Lane)
2936           continue;
2937         // This is set to true if we found a candidate for broadcast at Lane.
2938         bool FoundCandidate = false;
2939         for (unsigned OpI = 0, OpE = getNumOperands(); OpI != OpE; ++OpI) {
2940           OperandData &Data = getData(OpI, Ln);
2941           if (Data.APO != OpAPO || Data.IsUsed)
2942             continue;
2943           Value *OpILane = getValue(OpI, Lane);
2944           bool IsConstantOp = isa<Constant>(OpILane);
2945           // Consider the broadcast candidate if:
2946           // 1. Same value is found in one of the operands.
2947           if (Data.V == Op ||
2948               // 2. The operand in the given lane is not constant but there is a
2949               // constant operand in another lane (which can be moved to the
2950               // given lane). In this case we can represent it as a simple
2951               // permutation of constant and broadcast.
2952               (!IsConstantOp &&
2953                ((Lns > 2 && isa<Constant>(Data.V)) ||
2954                 // 2.1. If we have only 2 lanes, need to check that value in the
2955                 // next lane does not build same opcode sequence.
2956                 (Lns == 2 &&
2957                  !getSameOpcode({Op, getValue((OpI + 1) % OpE, Ln)}, TLI) &&
2958                  isa<Constant>(Data.V)))) ||
2959               // 3. The operand in the current lane is loop invariant (can be
2960               // hoisted out) and another operand is also a loop invariant
2961               // (though not a constant). In this case the whole vector can be
2962               // hoisted out.
2963               // FIXME: need to teach the cost model about this case for better
2964               // estimation.
2965               (IsInvariant && !isa<Constant>(Data.V) &&
2966                !getSameOpcode({Op, Data.V}, TLI) &&
2967                L->isLoopInvariant(Data.V))) {
2968             FoundCandidate = true;
2969             Data.IsUsed = Data.V == Op;
2970             if (Data.V == Op)
2971               ++Cnt;
2972             break;
2973           }
2974         }
2975         if (!FoundCandidate)
2976           return false;
2977       }
2978       return getNumLanes() == 2 || Cnt > 1;
2979     }
