1257 /// compatible instructions or constants, or just some other regular values.
1258 static bool areCompatibleCmpOps(Value *BaseOp0, Value *BaseOp1, Value *Op0,
1259                                 Value *Op1, const TargetLibraryInfo &TLI) {
1260   return (isConstant(BaseOp0) && isConstant(Op0)) ||
1261          (isConstant(BaseOp1) && isConstant(Op1)) ||
1262          (!isa<Instruction>(BaseOp0) && !isa<Instruction>(Op0) &&
1263           !isa<Instruction>(BaseOp1) && !isa<Instruction>(Op1)) ||
1264          BaseOp0 == Op0 || BaseOp1 == Op1 ||
