1269 /// \returns true if a compare instruction \p CI has similar "look" and
1270 /// same predicate as \p BaseCI, "as is" or with its operands and predicate
1271 /// swapped, false otherwise.
1272 static bool isCmpSameOrSwapped(const CmpInst *BaseCI, const CmpInst *CI,
1273                                const TargetLibraryInfo &TLI) {
1274   assert(BaseCI->getOperand(0)->getType() == CI->getOperand(0)->getType() &&
1275          "Assessing comparisons of different types?");
