1277   CmpInst::Predicate Pred = CI->getPredicate();
1278   CmpInst::Predicate SwappedPred = CmpInst::getSwappedPredicate(Pred);
1279 
1280   Value *BaseOp0 = BaseCI->getOperand(0);
1281   Value *BaseOp1 = BaseCI->getOperand(1);
1282   Value *Op0 = CI->getOperand(0);
1283   Value *Op1 = CI->getOperand(1);
1284 
1285   return (BasePred == Pred &&
1286           areCompatibleCmpOps(BaseOp0, BaseOp1, Op0, Op1, TLI)) ||
1287          (BasePred == SwappedPred &&
1288           areCompatibleCmpOps(BaseOp0, BaseOp1, Op1, Op0, TLI));
