1543 /// Shuffles \p Mask in accordance with the given \p SubMask.
1544 /// \param ExtendingManyInputs Supports reshuffling of the mask with not only
1545 /// one but two input vectors.
1546 static void addMask(SmallVectorImpl<int> &Mask, ArrayRef<int> SubMask,
1547                     bool ExtendingManyInputs = false) {
1548   if (SubMask.empty())
1549     return;
1550   assert(
1551       (!ExtendingManyInputs || SubMask.size() > Mask.size() ||
1552        // Check if input scalars were extended to match the size of other node.
1553        (SubMask.size() == Mask.size() && Mask.back() == PoisonMaskElem)) &&
1554       "SubMask with many inputs support must be larger than the mask.");
1555   if (Mask.empty()) {
1556     Mask.append(SubMask.begin(), SubMask.end());
1557     return;
1558   }
1559   SmallVector<int> NewMask(SubMask.size(), PoisonMaskElem);
1560   int TermValue = std::min(Mask.size(), SubMask.size());
1561   for (int I = 0, E = SubMask.size(); I < E; ++I) {
1562     if (SubMask[I] == PoisonMaskElem ||
1563         (!ExtendingManyInputs &&
1564          (SubMask[I] >= TermValue || Mask[SubMask[I]] >= TermValue)))
1565       continue;
1566     NewMask[I] = Mask[SubMask[I]];
1567   }
1568   Mask.swap(NewMask);
