1571 /// Order may have elements assigned special value (size) which is out of
1572 /// bounds. Such indices only appear on places which correspond to undef values
1573 /// (see canReuseExtract for details) and used in order to avoid undef values
1574 /// have effect on operands ordering.
1575 /// The first loop below simply finds all unused indices and then the next loop
1576 /// nest assigns these indices for undef values positions.
1577 /// As an example below Order has two undef positions and they have assigned
1578 /// values 3 and 7 respectively:
1579 /// before:  6 9 5 4 9 2 1 0
1580 /// after:   6 3 5 4 7 2 1 0
1581 static void fixupOrderingIndices(MutableArrayRef<unsigned> Order) {
1582   const unsigned Sz = Order.size();
1583   SmallBitVector UnusedIndices(Sz, /*t=*/true);
1584   SmallBitVector MaskedIndices(Sz);
1585   for (unsigned I = 0; I < Sz; ++I) {
1586     if (Order[I] < Sz)
1587       UnusedIndices.reset(Order[I]);
1588     else
1589       MaskedIndices.set(I);
1590   }
1591   if (MaskedIndices.none())
1592     return;
1593   assert(UnusedIndices.count() == MaskedIndices.count() &&
1594          "Non-synced masked/available indices.");
1595   int Idx = UnusedIndices.find_first();
1596   int MIdx = MaskedIndices.find_first();
1597   while (MIdx >= 0) {
1598     assert(Idx >= 0 && "Indices must be synced.");
1599     Order[MIdx] = Idx;
1600     Idx = UnusedIndices.find_next(Idx);
1601     MIdx = MaskedIndices.find_next(MIdx);
1602   }
1603 }
