3908     /// When ReuseReorderShuffleIndices is empty it just returns position of \p
3909     /// V within vector of Scalars. Otherwise, try to remap on its reuse index.
3910     int findLaneForValue(Value *V) const {
3911       unsigned FoundLane = getVectorFactor();
3912       for (auto *It = find(Scalars, V), *End = Scalars.end(); It != End;
3913            std::advance(It, 1)) {
3914         if (*It != V)
3915           continue;
3916         FoundLane = std::distance(Scalars.begin(), It);
3917         assert(FoundLane < Scalars.size() && "Couldn't find extract lane");
3918         if (!ReorderIndices.empty())
3919           FoundLane = ReorderIndices[FoundLane];
3920         assert(FoundLane < Scalars.size() && "Couldn't find extract lane");
3921         if (ReuseShuffleIndices.empty())
3922           break;
3923         if (auto *RIt = find(ReuseShuffleIndices, FoundLane);
3924             RIt != ReuseShuffleIndices.end()) {
3925           FoundLane = std::distance(ReuseShuffleIndices.begin(), RIt);
3926           break;
3927         }
3928       }
3929       assert(FoundLane < getVectorFactor() && "Unable to find given value.");
3930       return FoundLane;
