 891   struct InterchangeableInfo {
 892     const Instruction *I = nullptr;
 893     /// The bit it sets represents whether MainOp can be converted to.
 894     MaskType Mask = MainOpBIT | XorBIT | OrBIT | AndBIT | SubBIT | AddBIT |
 895                     MulBIT | AShrBIT | ShlBIT;
 896     /// We cannot create an interchangeable instruction that does not exist in
 897     /// VL. For example, VL [x + 0, y * 1] can be converted to [x << 0, y << 0],
 898     /// but << does not exist in VL. In the end, we convert VL to [x * 1, y *
 899     /// 1]. SeenBefore is used to know what operations have been seen before.
 900     MaskType SeenBefore = 0;
 901     InterchangeableInfo(const Instruction *I) : I(I) {}
 902     /// Return false allows BinOpSameOpcodeHelper to find an alternate
 903     /// instruction. Directly setting the mask will destroy the mask state,
 904     /// preventing us from determining which instruction it should convert to.
 905     bool trySet(MaskType OpcodeInMaskForm, MaskType InterchangeableMask) {
 906       if (Mask & InterchangeableMask) {
 907         SeenBefore |= OpcodeInMaskForm;
 908         Mask &= InterchangeableMask;
 909         return true;
 910       }
 911       return false;
 912     }
 913     bool equal(unsigned Opcode) {
