 957           ToCIValue = ToOpcode == Instruction::And
 958                           ? APInt::getAllOnes(FromCIValueBitWidth)
 959                           : APInt::getZero(FromCIValueBitWidth);
 960         }
 961         break;
 962       case Instruction::Mul:
 963         assert(FromCIValue.isPowerOf2() && "Cannot convert the instruction.");
