 968           ToCIValue = ToOpcode == Instruction::And
 969                           ? APInt::getAllOnes(FromCIValueBitWidth)
 970                           : APInt::getZero(FromCIValueBitWidth);
 971         }
 972         break;
 973       case Instruction::Add:
 974       case Instruction::Sub:
 975         if (FromCIValue.isZero()) {
 976           ToCIValue = APInt::getZero(FromCIValueBitWidth);
 977         } else {
 978           assert(is_contained({Instruction::Add, Instruction::Sub}, ToOpcode) &&
 979                  "Cannot convert the instruction.");
 980           ToCIValue = FromCIValue;
 981           ToCIValue.negate();
 982         }
 983         break;
 984       case Instruction::And:
 985         assert(FromCIValue.isAllOnes() && "Cannot convert the instruction.");
 986         ToCIValue = ToOpcode == Instruction::Mul
 987                         ? APInt::getOneBitSet(FromCIValueBitWidth, 0)
 988                         : APInt::getZero(FromCIValueBitWidth);
 989         break;
 990       default:
 991         assert(FromCIValue.isZero() && "Cannot convert the instruction.");
 992         ToCIValue = APInt::getZero(FromCIValueBitWidth);
 993         break;
 994       }
 995       Value *LHS = I->getOperand(1 - Pos);
 996       Constant *RHS =
 997           ConstantInt::get(I->getOperand(Pos)->getType(), ToCIValue);
 998       if (Pos == 1)
 999         return SmallVector<Value *>({LHS, RHS});
1000       return SmallVector<Value *>({RHS, LHS});
